window.__QUIZ_DATA__=[{"id":"theory>Biology>1997>1>a","subject":"Biology","year":"1997","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"Describe an experiment to compare the water-holding capacity of sandy, loamy and clayey soils.","images":[],"marking_scheme":"To perform an experiment to compare water holding capacity of sandy, loamy and clayey soil, one will need to obtain samples of sandy, loamy and clayey soils, dry soils samples or air dry samples to constant weight, insert funnels in the neck of the three measuring cylinders and place a folded filter paper or cotton wool in each of the funnels, put a known or equal weight of each of the air-dried soils in each of the funnels respectively and label them as sandy, loamy and clayey, pour equal amount of water into each soil and leave the set up till no more drops of water pass through it to the cylinder. Find the differences between the volume of water retained by each soil.    Observation: Sandy soil has more volume of water, followed by loamy soil and clayey soil in the cylinder.    Conclusion: Clayey soil has the greatest water retention capacity followed by loamy soil and sandy soil.","marks":"10","difficulty":"2"},{"id":"theory>Biology>1997>1>b","subject":"Biology","year":"1997","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"List three factors that may affect the water-holding capacity of soils.","images":[],"marking_scheme":"-Humus content/organic matter/living organisms  -Clay content  -Soil texture.  -size of soil particles  -mineral salt and pH","marks":"3","difficulty":"1"},{"id":"theory>Biology>1997>1>c>i","subject":"Biology","year":"1997","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"State the characteristics of sandy and loamy soils.","images":[],"marking_scheme":"-Sandy soil contains silica, large particles, low nutrients and low capillary power, retains little water, is porous / well drained, possesses coarse, gritty or rough texture and large air spaces and its mineral nutrients are easily leached.     -Loamy soil contains humus, organic matter, a mixture of sand clay and silt in about equal proportion and possesses moderate aeration, capillary power and water holding or retaining capacity.","marks":"4","difficulty":"1"},{"id":"theory>Biology>1997>1>c>ii","subject":"Biology","year":"1997","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"What type of vegetation does each support?","images":[],"marking_scheme":"Sandy soil supports scanty vegetation, grass or grassland and shrubs while loamy soil supports heavy or luxuriant vegetation (forest).","marks":"3","difficulty":"2"},{"id":"theory>Biology>1997>2>a>i","subject":"Biology","year":"1997","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"Explain the following terms:  first aid","images":[],"marking_scheme":"First aid is referred to as the assistance given to a victim of accidents or sudden illness in order to prevent worsening of condition before employing the services of a qualified doctor or physician.","marks":"2","difficulty":"1"},{"id":"theory>Biology>1997>2>a>ii","subject":"Biology","year":"1997","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Explain the following terms:   artificial respiration","images":[],"marking_scheme":"Artificial respiration involves the supply of air or oxygen to the lungs of a suffocating person to restore normal breathing or a method of resuscitating a person who suffers from asphyxia or lack of oxygen.","marks":"2","difficulty":"1"},{"id":"theory>Biology>1997>2>a>iii","subject":"Biology","year":"1997","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Explain the following terms:  dislocation","images":[],"marking_scheme":"Dislocation is the shifting or displacement of bones from joints or can be referred to as when bones forming a joint are displaced from their original positions.","marks":"2","difficulty":"2"},{"id":"theory>Biology>1997>2>a>iv","subject":"Biology","year":"1997","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Explain the following terms:   haemorrhage","images":[],"marking_scheme":"Haemorrhage is the escape or loss of blood or bleeding from a cut or punctured blood vessel.","marks":"2","difficulty":"2"},{"id":"theory>Biology>1997>2>b>i","subject":"Biology","year":"1997","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"State three objectives of first aid","images":[],"marking_scheme":"-To sustain life  -To save life or regain consciousness  -To reassure the victim of life  -To prevent the worsening of a condition of infection  -To reduce pain.","marks":"3","difficulty":"1"},{"id":"theory>Biology>1997>2>b>ii","subject":"Biology","year":"1997","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Explain the procedure for administering the mouth-to-mouth method of artificial respiration","images":[],"marking_scheme":"-Lie victim on the back and loosen all tight wears.  -Tilt the head back as far as possible and pull jaw forward to open the mouth.  -Ensure that you examine the mouth and pharynx well to remove any obstacles.  -Then open your mouth wide and place over the mouth of victim.  -Close victim's nostrils by pinching his nose with one of your hands.  -Take deep breath and blow in air gently (10 to 12 times a minute) into the victim's lungs until there is chest movement.","marks":"3","difficulty":"2"},{"id":"theory>Biology>1997>2>c>i","subject":"Biology","year":"1997","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"State three signs of dislocation.","images":[],"marking_scheme":"-Pain at the affected joint  -Swelling or tenderness around the affected joint  -Loss of function of the affected limb or loss of normal movement  -Deformity or abnormal appearance at the affected joint.","marks":"3","difficulty":"2"},{"id":"theory>Biology>1997>2>c>ii","subject":"Biology","year":"1997","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE","question":"Name two ways of stopping bleeding from an open wound.","images":[],"marking_scheme":"-direct pressure on the wound  -pressure at the pressure point  -use of iodine solution or methylated spirit  -use of bandage, use of tourniquet.","marks":"3","difficulty":"2"},{"id":"theory>Biology>1997>3>a>i","subject":"Biology","year":"1997","type":"Theory","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Make a labelled diagram of the female reproductive organ of a  flowering plant","images":["data:image/png;base64,"],"marking_scheme":"","marks":"7","difficulty":"3"},{"id":"theory>Biology>1997>3>a>ii","subject":"Biology","year":"1997","type":"Theory","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"Make a labelled diagram of the female reproductive organ of a   mammal.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"7","difficulty":"3"},{"id":"theory>Biology>1997>3>b","subject":"Biology","year":"1997","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"State the functions of any two of the labelled parts in (3a) (i) and (ii).","images":[],"marking_scheme":"Functions of Stigma in (a)(i) above is that it receives pollen grains and nourishes the pollen grains to germination while the Ovary houses the ovule or develops embryo or develops to fruit. The style serves as the passage way for germinating pollen grain to reach the ovule. The Ovule develops to seed after fertilization and Placenta connects ovule or seed to the ovary for nourishment.    (b)(ii) The ovary produces ovum/egg/hormones. The Funnel receives the ovum or egg. Fallopian tube or oviduct serves as a passage way for ovum or site of fertilization. The Uterus or womb houses the embryo till birth. The Vagina is the passage way for the baby during birth and it receives male organs (penis) and sperm during coition or intercourse. The Vulva is the entrance to the vagina. It receives male organ or penis and serves as a passage way for baby.","marks":"3","difficulty":"2"},{"id":"theory>Biology>1997>3>c","subject":"Biology","year":"1997","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"Compare reproduction in mammals, amphibians and birds with respect to  (i) number of eggs produced  (ii) method of fertilization  (iii) parental care.","images":[],"marking_scheme":"MammalsAmphibiansBirdsNo of eggsOne or fewManyMany or fewFertilizationInternalExternalInternalParental carePresent and last for a Iong timeAbsentPresent but for a short time","marks":"3","difficulty":"3"},{"id":"theory>Biology>1997>4>a","subject":"Biology","year":"1997","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION","question":"Define the term \" Conservation\".","images":[],"marking_scheme":"Conservation- can be referred to as the intelligent use or selection of what can be changed or replaced in the community without harmfully disturbing the balance in nature. In other words, it is the preservation of natural I resources from loss or waste, harm and exploitation through wise, rational or sensible use to ensure their availability and to preserve the quality or original nature of the natural resources.","marks":"2","difficulty":"1"},{"id":"theory>Biology>1997>4>b","subject":"Biology","year":"1997","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION","question":"State three reasons for conservation.","images":[],"marking_scheme":"-To prevent destruction of natural ecosystems  -For medicinal purposes .  -To preserve naturally beautiful scenarios for their aesthetic values.  -For research purposes  -To promote the recycling of some scarce mineral resources/ water  -To prevent destruction of natural environment  -To allow for continued use of natural resources for man's benefit  -Preservation of rare and valuable species of plant and animals for future generation or to save them from extinction.","marks":"3","difficulty":"2"},{"id":"theory>Biology>1997>4>c>i","subject":"Biology","year":"1997","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"List four methods of conserving each of the following: water","images":[],"marking_scheme":"-Trapping or storage in tanks or wells  -Treatment and recycling of used water  -Damming of rivers to allow more effective management of water  -Planting of trees to provide vegetation cover which reduces evaporation and promotes water retention in soil /rainfall.  -Saving of water by prompt repairs of burst pipes and turning off taps immediately after use.","marks":"4","difficulty":"2"},{"id":"theory>Biology>1997>4>c>ii","subject":"Biology","year":"1997","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"List four methods of conserving each of the following: wildlife","images":[],"marking_scheme":"-Establishment of zoological gardens  -Establishment of game /forest reserves  -Hunting should be controlled  -Prohibiting bush burning  -Prohibiting killing or poaching of animals in game reserves  -Educating the public on the values of wildlife  -Discouraging deforestation and encouraging afforestation.","marks":"4","difficulty":"2"},{"id":"theory>Biology>1997>4>c>iii","subject":"Biology","year":"1997","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"List four methods of conserving each of the following: forest.","images":[],"marking_scheme":"-Ensure cutting of trees without destroying undergrowth.  -Reafforestation or tree planting should be encouraged.  -Discourage bush burning.  -Pests /diseases of plants should be controlled.  -Establishment of forest reserve  -Educating the public on the value of forest and importance of conservation and cutting of matured trees only.","marks":"4","difficulty":"1"},{"id":"theory>Biology>1997>4>d","subject":"Biology","year":"1997","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"Mention three forest or game reserves in Nigeria.","images":[],"marking_scheme":"- Yankari game reserve in Bauchi State  -Borgu game reserve in Niger State  -Omo forest reserve in Ogun State  -Sakpoba forest reserve in Edo State  -Mamu River in Anambra State  -Anara in Kaduna State  -Zamfara in Zamfara State  -Sanga River Plateau State  -Olomu forest reserve - Kwara State  -ljero forest reserve in Ekiti.","marks":"3","difficulty":"1"}];